import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import java.io.StringReader;

@WebService
public class SOAPService {

    @WebMethod
    public String processXML(String xml) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new StringReader(xml));

            Element rootElement = document.getDocumentElement();
            // Process the XML structure here
            // Example: Extract data from nested entities
            String data = extractData(rootElement);

            return "Processed Data: " + data;
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing XML";
        }
    }

    private String extractData(Element element) {
        StringBuilder dataBuilder = new StringBuilder();
        NodeList nodeList = element.getChildNodes();
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node node = nodeList.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) node;
                dataBuilder.append(childElement.getNodeName()).append(": ").append(childElement.getTextContent()).append("\n");
                // Recursively process nested elements
                dataBuilder.append(extractData(childElement));
            }
        }
        return dataBuilder.toString();
    }
}